package com.wotb.web.boost.controller;

import com.wotb.web.boost.dto.BoostAssignmentDto;
import com.wotb.web.boost.service.BoostAssignmentService;
import com.wotb.web.boost.service.BoosterService;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

/** µēōµēŗĶ¦åĶ¦ÆĶ«óÕŹĢµÄźÕÅŻŃĆéµĀ╣µŹ« JWT Ķć¬ÕŖ©Ķ»åÕł½µēōµēŗĶ║½õ╗ĮÕ╣ČĶ┐öÕø×ÕģČÕłåķģŹŃĆé */
@RestController
@RequestMapping("/api/booster")
public class BoosterAssignmentController {

    private final BoostAssignmentService assignmentService;
    private final BoosterService boosterService;

    public BoosterAssignmentController(final BoostAssignmentService assignmentService,
                                       final BoosterService boosterService) {
        this.assignmentService = assignmentService;
        this.boosterService = boosterService;
    }

    @GetMapping("/assignments")
    public List<BoostAssignmentDto> myAssignments(
            final org.springframework.security.oauth2.jwt.Jwt jwt) {
        final String keycloakUserId = jwt.getSubject();
        final var boosterOpt = boosterService.findByKeycloakUserId(keycloakUserId);
        if (boosterOpt.isEmpty()) return List.of();
        return assignmentService.findByBooster(boosterOpt.get().id());
    }
}
```

